"use client";
import { PixelCircle } from "./pixel-circle";
import { Zanjo } from "./zanjo";
import { EnhancedPixelCube } from "./enhanced-pixel-cube";

export function MousePixelation() {
  return <PixelCircle />;
}

export { PixelCircle, Zanjo, EnhancedPixelCube };

"use client";
import React, { useRef, useEffect } from "react";
import { Canvas, extend, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { Bloom, EffectComposer } from "@react-three/postprocessing";

class PixelTrailMaterial extends THREE.ShaderMaterial {
  constructor() {
    super({
      uniforms: {
        uTime: { value: 0 },
        uMouse: { value: new THREE.Vector2(0.5, 0.5) },
        uPrevMouse: { value: new THREE.Vector2(0.5, 0.5) },
        uHover: { value: 0.0 },
        uBasePixels: { value: 35.0 },
        uMouseVelocity: { value: new THREE.Vector2(0, 0) },
        uTrailStrength: { value: 0.0 },
      },
      vertexShader: `
        varying vec2 vUv;
        varying vec3 vPosition;
        uniform float uTime;
        uniform vec2 uMouse;
        uniform vec2 uPrevMouse;
        uniform float uHover;
        uniform float uBasePixels;
        uniform vec2 uMouseVelocity;
        uniform float uTrailStrength;

        float noise2D(vec2 p){
          vec2 ip = floor(p);
          vec2 f = fract(p);
          f = f * (3.0 - 2.0 * f);
          float n00 = sin(dot(ip, vec2(12.9898, 78.233)));
          float n10 = sin(dot(ip + vec2(1., 0.), vec2(12.9898, 78.233)));
          float n01 = sin(dot(ip + vec2(0., 1.), vec2(12.9898, 78.233)));
          float n11 = sin(dot(ip + vec2(1., 1.), vec2(12.9898, 78.233)));
          float nx0 = mix(n00, n10, f.x);
          float nx1 = mix(n01, n11, f.x);
          return mix(nx0, nx1, f.y) * 0.5 + 0.5;
        }

        float easeInOutCubic(float t) {
          return t < 0.5 ? 4.0 * t * t * t : 1.0 - pow(-2.0 * t + 2.0, 3.0) / 2.0;
        }

        float trailDistance(vec2 point, vec2 mousePos, vec2 velocity) {
          vec2 toPoint = point - mousePos;
          float velocityMag = length(velocity);
          if (velocityMag < 0.001) return length(toPoint);
          vec2 velocityDir = normalize(velocity);
          float alongTrail = dot(toPoint, velocityDir);
          float perpDist = length(toPoint - velocityDir * alongTrail);
          float trailLength = velocityMag * 15.0;
          if (alongTrail > 0.0 && alongTrail < trailLength) return perpDist;
          else if (alongTrail <= 0.0) return length(toPoint);
          else return length(toPoint - velocityDir * trailLength);
        }

        void main(){
          vUv = uv;
          vPosition = position;
          vec3 pos = position;
          vec2 pixelUV = floor(uv * uBasePixels) / uBasePixels;
          float dist = trailDistance(pixelUV, uMouse, uMouseVelocity);
          float hoverRadius = 0.15 + length(uMouseVelocity) * 0.3;
          float hoverEffect = smoothstep(hoverRadius, 0.0, dist) * uHover * uTrailStrength;
          hoverEffect = easeInOutCubic(hoverEffect);
          float noiseValue = noise2D(pixelUV * 8.0 + uTime * 0.3);
          float maxExtrusion = 0.8;
          float extrusion = hoverEffect * (0.6 + noiseValue * 0.4) * maxExtrusion;
          float animationDelay = dist * 2.0;
          float animatedHover = max(0.0, uHover - animationDelay * 0.1);
          animatedHover = clamp(animatedHover * 1.5, 0.0, 1.0);
          extrusion *= easeInOutCubic(animatedHover);
          pos.z += extrusion;
          pos.x += sin(pixelUV.x * 40.0) * hoverEffect * 0.008;
          pos.y += cos(pixelUV.y * 40.0) * hoverEffect * 0.008;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
        }
      `,
      fragmentShader: `
        uniform float uTime;
        uniform vec2 uMouse;
        uniform float uHover;
        uniform float uBasePixels;
        uniform vec2 uMouseVelocity;
        uniform float uTrailStrength;
        varying vec2 vUv;
        varying vec3 vPosition;

        float trailDistance(vec2 point, vec2 mousePos, vec2 velocity) {
          vec2 toPoint = point - mousePos;
          float velocityMag = length(velocity);
          if (velocityMag < 0.001) return length(toPoint);
          vec2 velocityDir = normalize(velocity);
          float alongTrail = dot(toPoint, velocityDir);
          float perpDist = length(toPoint - velocityDir * alongTrail);
          float trailLength = velocityMag * 15.0;
          if (alongTrail > 0.0 && alongTrail < trailLength) return perpDist;
          else if (alongTrail <= 0.0) return length(toPoint);
          else return length(toPoint - velocityDir * trailLength);
        }

        float easeInOutCubic(float t) {
          return t < 0.5 ? 4.0 * t * t * t : 1.0 - pow(-2.0 * t + 2.0, 3.0) / 2.0;
        }

        void main(){
          vec2 uv = vUv;
          vec2 pixelUV = floor(uv * uBasePixels) / uBasePixels;
          float dist = trailDistance(pixelUV, uMouse, uMouseVelocity);
          float hoverRadius = 0.15 + length(uMouseVelocity) * 0.3;
          float hoverEffect = smoothstep(hoverRadius, 0.0, dist) * uHover * uTrailStrength;
          hoverEffect = easeInOutCubic(hoverEffect);
          float depthShading = 1.0 + vPosition.z * 0.3;
          vec3 topColor = vec3(0.0, 0.0, 0.0);
          vec3 sideColor = vec3(0.01, 0.01, 0.01);
          float topFaceFactor = smoothstep(0.7, 1.0, normalize(vPosition).z);
          vec3 cubeColor = mix(sideColor, topColor, topFaceFactor);
          float light = 0.5 + 0.5 * dot(normalize(vec3(0.3, 0.5, 1.0)), normalize(vPosition + vec3(0.0, 0.0, 1.0)));
          cubeColor *= light;
          vec2 pixelCenter = (floor(uv * uBasePixels) + 0.5) / uBasePixels;
          vec2 pixelOffset = abs(uv - pixelCenter) * uBasePixels;
          float border = step(0.45, max(pixelOffset.x, pixelOffset.y));
          cubeColor = mix(cubeColor, vec3(0.0), border * 0.9);
          float vig = 1.0 - smoothstep(0.3, 3.2, length(uv - 0.5) * 2.0);
          cubeColor *= mix(1.0, vig, 0.6);
          gl_FragColor = vec4(cubeColor * depthShading, 1.0);
        }
      `,
    });
  }
}

extend({ PixelTrailMaterial });

class CubeDeformMaterial extends THREE.ShaderMaterial {
  constructor(color, emissive) {
    super({
      uniforms: {
        uColor: { value: color },
        uEmissive: { value: emissive },
        uEmissiveIntensity: { value: 2.4 },
      },
      vertexShader: `
        varying vec2 vUv;
        varying vec3 vNormal;
        varying vec3 vPosition;
        void main() {
          vUv = uv;
          vNormal = normalize(normalMatrix * normal);
          vPosition = position;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        uniform vec3 uColor;
        uniform vec3 uEmissive;
        uniform float uEmissiveIntensity;
        varying vec2 vUv;
        varying vec3 vNormal;
        varying vec3 vPosition;
        void main() {
          vec3 lightDir = normalize(vec3(1.0, 1.0, 1.0));
          float diff = max(dot(vNormal, lightDir), 0.0);
          vec3 litColor = uColor * (0.3 + 0.7 * diff);
          vec3 finalColor = litColor + (uEmissive * uEmissiveIntensity * 0.9);
          gl_FragColor = vec4(finalColor, 1.0);
        }
      `,
    });
  }
}

extend({ CubeDeformMaterial });

function PixelGrid({ mousePositionRef, mouseVelocityRef, trailStrengthRef }) {
  const matRef = useRef();
  const meshRef = useRef();
  const pointerTarget = useRef({ x: 0.5, y: 0.5 });
  const pointerCurrent = useRef({ x: 0.5, y: 0.5 });
  const lastPointerPos = useRef({ x: 0.5, y: 0.5 });
  const isMoving = useRef(false);
  const lastMoveTime = useRef(0);
  const movementThreshold = 0.001;

  const onPointerMove = (e) => {
    const [u, v] = e.uv;
    const currentTime = Date.now();
    const moved =
      Math.abs(u - lastPointerPos.current.x) > movementThreshold ||
      Math.abs(v - lastPointerPos.current.y) > movementThreshold;
    if (moved) {
      pointerTarget.current.x = u;
      pointerTarget.current.y = v;
      lastPointerPos.current.x = u;
      lastPointerPos.current.y = v;
      lastMoveTime.current = currentTime;
      isMoving.current = true;
    }
    mousePositionRef.current.x = u;
    mousePositionRef.current.y = v;
  };

  useFrame((state) => {
    if (!matRef.current) return;
    const time = state.clock.getElapsedTime();
    matRef.current.uniforms.uTime.value = time;
    if (Date.now() - lastMoveTime.current > 500) isMoving.current = false;

    const oldX = pointerCurrent.current.x;
    const oldY = pointerCurrent.current.y;
    pointerCurrent.current.x += (pointerTarget.current.x - pointerCurrent.current.x) * 0.1;
    pointerCurrent.current.y += (pointerTarget.current.y - pointerCurrent.current.y) * 0.1;

    const velocityX = pointerCurrent.current.x - oldX;
    const velocityY = pointerCurrent.current.y - oldY;
    mouseVelocityRef.current.x = mouseVelocityRef.current.x * 0.8 + velocityX * 0.2;
    mouseVelocityRef.current.y = mouseVelocityRef.current.y * 0.8 + velocityY * 0.2;

    matRef.current.uniforms.uMouse.value.set(pointerCurrent.current.x, pointerCurrent.current.y);
    matRef.current.uniforms.uMouseVelocity.value.set(
      mouseVelocityRef.current.x,
      mouseVelocityRef.current.y
    );

    const hv = matRef.current.uniforms.uHover.value;
    const target = isMoving.current ? 1 : 0;
    const transitionSpeed = isMoving.current ? 0.06 : 0.008;
    matRef.current.uniforms.uHover.value += (target - hv) * transitionSpeed;

    const velocityMag = Math.sqrt(velocityX * velocityX + velocityY * velocityY);
    const targetTrail = Math.min(1.0, velocityMag * 50.0 + 0.3);
    trailStrengthRef.current += (targetTrail - trailStrengthRef.current) * 0.1;
    matRef.current.uniforms.uTrailStrength.value = trailStrengthRef.current;

    mousePositionRef.current.x = pointerCurrent.current.x;
    mousePositionRef.current.y = pointerCurrent.current.y;
  });

  return (
    <mesh ref={meshRef} onPointerMove={onPointerMove}>
      <planeGeometry args={[18, 12, 200, 200]} />
      <pixelTrailMaterial ref={matRef} color={new THREE.Color(0x000000)} />
    </mesh>
  );
}

function DeformingCube({ mousePositionRef, mouseVelocityRef, trailStrengthRef }) {
  const cubeRef = useRef();
  const geometryRef = useRef();
  const originalPositions = useRef(null);
  const targetRotation = useRef({ x: 0, y: 0 });
  const currentRotation = useRef({ x: 0, y: 0 });
  const materialRef = useRef();
  const { camera } = useThree();

  const colorOptions = [
    { color: new THREE.Color("#39FF14"), emissive: new THREE.Color("#39FF14") },
    { color: new THREE.Color("aqua"), emissive: new THREE.Color("aqua") },
    { color: new THREE.Color("#FFD600"), emissive: new THREE.Color("#FFD600") },
  ];

  const colorState = useRef({
    current: colorOptions[0].color.clone(),
    target: colorOptions[0].color.clone(),
    currentEmissive: colorOptions[0].emissive.clone(),
    targetEmissive: colorOptions[0].emissive.clone(),
    lastSwitch: Date.now(),
    interval: 1200 + Math.random() * 5000,
  });

  useEffect(() => {
    if (cubeRef.current) {
      const geometry = cubeRef.current.geometry;
      geometryRef.current = geometry;
      originalPositions.current = geometry.attributes.position.array.slice();
    }
  }, []);

  useFrame(() => {
    if (!cubeRef.current || !geometryRef.current || !originalPositions.current) return;

    const now = Date.now();
    if (now - colorState.current.lastSwitch > colorState.current.interval) {
      let nextIdx = Math.floor(Math.random() * colorOptions.length);
      const currentIndex = colorOptions.findIndex((opt) =>
        opt.emissive.equals(colorState.current.targetEmissive)
      );
      if (nextIdx === currentIndex) nextIdx = (nextIdx + 1) % colorOptions.length;
      colorState.current.target.copy(colorOptions[nextIdx].color);
      colorState.current.targetEmissive.copy(colorOptions[nextIdx].emissive);
      colorState.current.lastSwitch = now;
      colorState.current.interval = 1200 + Math.random() * 5000;
    }

    colorState.current.current.lerp(colorState.current.target, 0.1);
    colorState.current.currentEmissive.lerp(colorState.current.targetEmissive, 0.1);

    if (materialRef.current) {
      materialRef.current.uniforms.uColor.value.copy(colorState.current.current);
      materialRef.current.uniforms.uEmissive.value.copy(colorState.current.currentEmissive);
    }

    targetRotation.current.x = (mousePositionRef.current.y - 0.5) * Math.PI / 2;
    targetRotation.current.y = (mousePositionRef.current.x - 0.5) * Math.PI / 1.5;
    currentRotation.current.x += (targetRotation.current.x - currentRotation.current.x) * 0.12;
    currentRotation.current.y += (targetRotation.current.y - currentRotation.current.y) * 0.12;
    cubeRef.current.rotation.x = currentRotation.current.x;
    cubeRef.current.rotation.y = currentRotation.current.y;

    const cubeWorldPos = new THREE.Vector3();
    cubeRef.current.getWorldPosition(cubeWorldPos);
    cubeWorldPos.project(camera);
    const cubeScreenX = (cubeWorldPos.x + 1) / 2;
    const cubeScreenY = (cubeWorldPos.y + 1) / 2;
    const distToCube = Math.sqrt(
      Math.pow(mousePositionRef.current.x - cubeScreenX, 2) +
        Math.pow(mousePositionRef.current.y - cubeScreenY, 2)
    );
    const deformStrength = Math.max(0, 1 - distToCube / 2.0) * trailStrengthRef.current;

    const positions = geometryRef.current.attributes.position.array;
    const time = Date.now() * 0.003;
    for (let i = 0; i < positions.length; i += 3) {
      const x = originalPositions.current[i];
      const y = originalPositions.current[i + 1];
      const z = originalPositions.current[i + 2];
      const distFromCenter = Math.sqrt(x * x + y * y + z * z);
      const wave = Math.sin(distFromCenter * 8.0 - time * 3.0) * 0.15;
      const ripple = wave * deformStrength;
      const velocityInfluence =
        (x * mouseVelocityRef.current.x + y * mouseVelocityRef.current.y) * 100.0;
      const deformation = (ripple + velocityInfluence * deformStrength) * 0.3;
      positions[i] = x + x * deformation;
      positions[i + 1] = y + y * deformation;
      positions[i + 2] = z + z * deformation;
    }
    geometryRef.current.attributes.position.needsUpdate = true;
    geometryRef.current.computeVertexNormals();
  });

  return (
    <mesh ref={cubeRef} position={[0, 0, 1]} layers={1}>
      <boxGeometry args={[1, 1, 1, 20, 20, 20]} />
      <cubeDeformMaterial
        ref={materialRef}
        args={[new THREE.Color("#ffffff"), new THREE.Color("#ffffff")]}
      />
    </mesh>
  );
}

export function EnhancedPixelCube() {
  const mousePositionRef = useRef({ x: 0.5, y: 0.5 });
  const mouseVelocityRef = useRef({ x: 0, y: 0 });
  const trailStrengthRef = useRef(0);

  return (
    <div style={{ width: "100vw", height: "100vh", background: "#000" }}>
      <Canvas
        camera={{ position: [0, 0, 4], fov: 75 }}
        gl={{ antialias: true }}
        onCreated={({ camera }) => {
          camera.layers.enable(1);
        }}
      >
        <PixelGrid
          mousePositionRef={mousePositionRef}
          mouseVelocityRef={mouseVelocityRef}
          trailStrengthRef={trailStrengthRef}
        />
        <EffectComposer>
          <Bloom
            intensity={1}
            luminanceThreshold={1.5}
            luminanceSmoothing={0.5}
            height={0}
            layers={[1]}
          />
        </EffectComposer>
        <DeformingCube
          mousePositionRef={mousePositionRef}
          mouseVelocityRef={mouseVelocityRef}
          trailStrengthRef={trailStrengthRef}
        />
      </Canvas>
    </div>
  );
}

"use client";
import React, { useRef, useEffect } from "react";
import { Canvas, extend, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import gsap from "gsap";
import ScrollTrigger from "gsap/dist/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

class PixelCirclesMaterial extends THREE.ShaderMaterial {
  constructor() {
    super({
      uniforms: {
        uTime: { value: 0 },
        uMouse: { value: new THREE.Vector2(0.5, 0.5) },
        uHover: { value: 0.7 },
        uBasePixels: { value: 35.0 },
        uDynamicRange: { value: 0.02 },
        uNoiseStrength: { value: 0.05 },
        uDisplacement: { value: 0.02 },
        uColorBoost: { value: 0.0 },
        uVignette: { value: 0.6 },
        uResolution: { value: new THREE.Vector2(2, 2) },
        uCircle1Center: { value: new THREE.Vector2(0.3, 0.5) },
        uCircle2Center: { value: new THREE.Vector2(0.7, 0.5) },
      },
      vertexShader: /* glsl */ `
        varying vec2 vUv;
        void main(){
          vUv = uv;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
        }
      `,
      fragmentShader: /* glsl */ `
        uniform float uTime;
        uniform vec2  uMouse;
        uniform float uHover;
        uniform float uBasePixels;
        uniform float uDynamicRange;
        uniform float uNoiseStrength;
        uniform float uDisplacement;
        uniform float uColorBoost;
        uniform float uVignette;
        uniform vec2  uResolution;
        uniform vec2  uCircle1Center;
        uniform vec2  uCircle2Center;
        varying vec2 vUv;

        float noise2D(vec2 p){
          vec2 ip = floor(p);
          vec2 f = fract(p);
          f = f*(3.0 - 2.0*f);
          vec4 h = vec4(0., 1., 0., 1.);
          vec4 n = h.xyzy * ip.x + h.xxzz * ip.y;
          n = sin(n * vec4(12.9898,78.233,45.164,94.673));
          return dot(mix(n.xy, n.zw, f.y), mix(h.xz, h.yw, f.x)) * 0.1 + 0.5;
        }

        vec2 pixelate(vec2 uv, float pixels){
          vec2 pixelUV = floor(uv * pixels)/pixels;
          float n = fract(sin(dot(floor(pixelUV*10.),vec2(12.9898,78.233))) * 43758.5453) * uNoiseStrength * 0.9;
          return pixelUV + n * uHover;
        }

        void main(){
          vec2 uv = vUv;
          float dist = distance(uv, uMouse);
          float time = uTime * 2.0;
          float dynamicPixels = uBasePixels*(1.0 + sin(time)*uDynamicRange);
          float finalPixels = mix(uBasePixels, dynamicPixels, smoothstep(0.5,0.0, dist)*uHover);

          vec2 disp = vec2(
            noise2D(uv + time),
            noise2D(uv*3.0 + time + 1.0)
          ) * uDisplacement * uHover;

          vec2 pixelatedUV = mix(
            uv + disp,
            pixelate(uv + disp, finalPixels),
            smoothstep(0.20,0.0, dist) * 3.0 * uHover
          );

          float c1 = smoothstep(0.5, 0.0, distance(pixelatedUV, uCircle1Center));
          float c2 = smoothstep(0.5, 0.0, distance(pixelatedUV, uCircle2Center));

          vec3 color = mix(
            vec3(0.0),
            mix(vec3(0.0, 0.5, 0.7), vec3(0.5, 0.1, 0.8), c2),
            c1
          );

          float vig = 1.0 - smoothstep(0.3,3.2, length(uv-0.5)*2.0);
          gl_FragColor = vec4(color * mix(1.0, vig, uVignette), 1.0);
        }
      `,
    });
  }
}

extend({ PixelCirclesMaterial });

function PixelCirclesPlane() {
  const matRef = useRef();
  const pointer = useRef({ target: { x: 0.5, y: 0.5 }, current: { x: 0.5, y: 0.5 } });
  const hover = useRef(false);

  useEffect(() => {
    const onResize = () => {
      matRef.current?.uniforms.uResolution.value.set(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", onResize);
    onResize();
    return () => window.removeEventListener("resize", onResize);
  }, []);

  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.from(".pc-text-left", { xPercent: -25, duration: 3.5, ease: "expo.out" });
      gsap.from(".pc-text-right", { xPercent: 25, duration: 3.5, ease: "expo.out" });

      gsap
        .timeline({
          scrollTrigger: {
            trigger: ".pc-logo-container",
            start: "top top",
            end: "+150% top",
            scrub: true,
            pin: true,
          },
        })
        .to(".pc-logo", { rotate: 90, scale: 20, duration: 2, ease: "power3.in" })
        .to(".pc-logo", { opacity: 0, duration: 1.5, ease: "power2.in" }, "<0.5");
    });
    return () => ctx.revert();
  }, []);

  useFrame(({ clock }) => {
    if (!matRef.current) return;
    const time = clock.getElapsedTime();
    const { target, current } = pointer.current;
    const { uniforms } = matRef.current;
    uniforms.uTime.value = time;
    current.x += (target.x - current.x) * 0.1;
    current.y += (target.y - current.y) * 0.1;
    uniforms.uMouse.value.set(current.x, current.y);
    uniforms.uHover.value += ((hover.current ? 1 : 0) - uniforms.uHover.value) * 0.05;
    uniforms.uCircle1Center.value.set(
      0.5 + 0.2 * Math.sin(time * 0.3),
      0.5 + 0.2 * Math.cos(time * 0.3)
    );
    uniforms.uCircle2Center.value.set(
      0.5 + 0.3 * Math.sin(time * 0.1),
      0.5 + 0.15 * Math.cos(time * 0.8)
    );
  });

  return (
    <mesh
      onPointerEnter={() => (hover.current = true)}
      onPointerLeave={() => (hover.current = false)}
      onPointerMove={(e) => {
        const [u, v] = e.uv;
        pointer.current.target = { x: u, y: v };
      }}
    >
      <planeGeometry args={[18, 12]} />
      <pixelCirclesMaterial ref={matRef} />
    </mesh>
  );
}

export function PixelCircle() {
  return (
    <div className="relative w-screen h-screen overflow-hidden">
      <div className="fixed top-0 left-0 h-full w-full overflow-hidden">
        <Canvas>
          <PixelCirclesPlane />
        </Canvas>
      </div>

      <section className="w-full h-screen relative z-[10] flex flex-col justify-center px-[5vw] gap-[4vw] pointer-events-none">
        <h1 className="text-white font-medium text-[9vw] mt-[4vw] leading-[1.2] flex flex-col">
          <span className="pc-text-left text-left">
            Redefining <span className="font-light">Value.</span>
          </span>
          <span className="pc-text-right text-right font-light">
            Rewiring <span className="font-medium">the Future.</span>
          </span>
        </h1>
        <p className="text-white text-[1.5vw] w-[30%] text-justify">
          The decentralized economy starts here where speed, security, and sovereignty collide.
        </p>
      </section>
    </div>
  );
}

"use client";
import { useRef, useEffect, useMemo } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";

const vertexShader = () => `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = () => `
  uniform vec2 uMouse;
  uniform vec2 uVelocity;
  uniform float uBlockSize;
  uniform float uRadius;
  uniform float uIntensity;
  uniform float uTime;
  uniform float uIsMoving;
  uniform sampler2D uTexture;
  varying vec2 vUv;

  void main() {
    vec2 uv = vUv;

    vec2 blockCoord = floor(uv / uBlockSize) * uBlockSize + (uBlockSize * 0.5);
    blockCoord += sin(uTime * 0.3) * 0.002 + cos(uTime * 0.4) * 0.001;

    float dist = distance(blockCoord, uMouse);
    float smoothDist = smoothstep(uRadius * 1.2, 0.0, dist);

    float influence = smoothDist * (1.0 - dist / (uRadius * 1.2));
    influence *= 1.0 + sin(uTime * 1.5) * 0.15 + cos(uTime * 2.3) * 0.05;
    influence *= smoothstep(0.0, 1.0, uIsMoving);

    vec2 dir = uVelocity;
    float blend = smoothstep(-0.05, 0.15, abs(uVelocity.x) - abs(uVelocity.y));
    dir = mix(
      vec2(0.0, sign(uVelocity.y)),
      vec2(sign(uVelocity.x), 0.0),
      blend
    );

    vec2 displacement = dir * influence * uBlockSize * uIntensity;
    displacement *= 1.0 + sin(uTime * 0.8) * 0.2 + cos(uTime * 1.2) * 0.1;

    vec2 displacedUV = uv - displacement;
    displacedUV += sin(displacedUV.x * 8.0 + uTime) * 0.002
                 + cos(displacedUV.y * 6.0 + uTime * 0.8) * 0.001;

    vec4 color = texture2D(uTexture, displacedUV);
    color.rgb *= 1.0 + influence * 0.1;

    gl_FragColor = color;
  }
`;

function PlaneWithShader({ texture }) {
  const materialRef = useRef();
  const { size, viewport } = useThree();
  const clock = useRef(new THREE.Clock());
  const isMovingRef = useRef(1.0);
  const moveTimeoutRef = useRef(null);
  const mouseRef = useRef(new THREE.Vector2(0.5, 0.5));
  const velocityRef = useRef(new THREE.Vector2(0.0, 0.0));
  const lastMouseRef = useRef(new THREE.Vector2(0.5, 0.5));
  const targetMouseRef = useRef(new THREE.Vector2(0.5, 0.5));
  const targetVelocityRef = useRef(new THREE.Vector2(0.0, 0.0));
  const smoothedVelocityRef = useRef(new THREE.Vector2(0.0, 0.0));

  const shaderMaterial = useMemo(
    () =>
      new THREE.ShaderMaterial({
        uniforms: {
          uMouse: { value: new THREE.Vector2(0.5, 0.5) },
          uVelocity: { value: new THREE.Vector2(0.0, 0.5) },
          uBlockSize: { value: 1.0 / 35.0 },
          uRadius: { value: 0.3 },
          uIntensity: { value: 1.8 },
          uTime: { value: 2 },
          uIsMoving: { value: 1.0 },
          uTexture: { value: texture },
        },
        vertexShader: vertexShader(),
        fragmentShader: fragmentShader(),
        transparent: false,
      }),
    [texture]
  );

  useEffect(() => {
    const handleMouseMove = (e) => {
      const newMouse = new THREE.Vector2(
        e.clientX / size.width,
        1.0 - e.clientY / size.height
      );
      const vel = newMouse.clone().sub(lastMouseRef.current);
      targetMouseRef.current.copy(newMouse);
      targetVelocityRef.current.copy(vel.multiplyScalar(35.0));
      lastMouseRef.current.copy(newMouse);
      isMovingRef.current = 1.0;
      if (moveTimeoutRef.current) clearTimeout(moveTimeoutRef.current);
      moveTimeoutRef.current = setTimeout(() => {
        isMovingRef.current = 0.0;
      }, 300);
    };
    window.addEventListener("mousemove", handleMouseMove, { passive: true });
    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      if (moveTimeoutRef.current) clearTimeout(moveTimeoutRef.current);
    };
  }, [size]);

  useFrame(() => {
    shaderMaterial.uniforms.uTime.value = clock.current.getElapsedTime();
    const currentMouse = shaderMaterial.uniforms.uMouse.value;
    currentMouse.lerp(targetMouseRef.current, 0.15);
    smoothedVelocityRef.current.lerp(targetVelocityRef.current, 0.06);
    const currentVelocity = shaderMaterial.uniforms.uVelocity.value;
    currentVelocity.lerp(smoothedVelocityRef.current, 0.15);
    targetVelocityRef.current.multiplyScalar(0.96);
    shaderMaterial.uniforms.uIsMoving.value = THREE.MathUtils.lerp(
      shaderMaterial.uniforms.uIsMoving.value,
      isMovingRef.current,
      0.05
    );
  });

  const imageAspect = 1920 / 1080;
  const viewportAspect = viewport.width / viewport.height;
  let planeWidth, planeHeight;
  if (imageAspect > viewportAspect) {
    planeWidth = viewport.width;
    planeHeight = viewport.width / imageAspect;
  } else {
    planeHeight = viewport.height;
    planeWidth = viewport.height * imageAspect;
  }

  return (
    <mesh>
      <planeGeometry args={[planeWidth, planeHeight]} />
      <primitive object={shaderMaterial} attach="material" ref={materialRef} />
    </mesh>
  );
}

function Scene({ img }) {
  const texture = useMemo(() => new THREE.TextureLoader().load(img), [img]);
  return <PlaneWithShader texture={texture} />;
}

export function Zanjo({ img = "/assets/pixelation/zanjo.jpg" }) {
  return (
    <div className="h-screen w-full relative">
      <Canvas camera={{ position: [0, 0, 5], fov: 45 }}>
        <color attach="background" args={["#000000"]} />
        <Scene img={img} />
      </Canvas>
    </div>
  );
}
